	@Test
	void prefixDirectLookupWithUnboundTrailingComponentDoesNotCapFanoutToOneProbeRow() throws Exception {
		LmdbEvaluationStatistics statistics = new LmdbEvaluationStatistics(null, null, null, null, null, null);
		Object productEstimate = boundJoinProductEstimate(430_900.0d, 20_000.0d, 745_100.0d, 16_100_000.0d,
				"target", false);
		JoinFactorCostModel.FactorCostEstimate baseEstimate = directSubjectPredicateProbeEstimate();

		Object blend = invokeBlend(statistics, productEstimate, 430_900.0d, 430_900.0d, 20_000.0d, 21.545d,
				21.545d, baseEstimate);

		assertNotNull(blend, "The access-path envelope should still contribute a comparison signal.");
		assertNotEquals("access_path_transition_envelope", stringRecordValue(blend, "fusion"),
				"A direct [S,P] lookup with an unbound object is a prefix lookup, not an exact statement envelope.");
		assertTrue(doubleRecordValue(blend, "outputRows") > 20_000.0d,
				"Prefix lookup fanout must be allowed to exceed one output row per repeated invocation.");
	}

	@Test
	void exactDirectLookupCanApplyTupleSketchSelectivityBelowProbeEnvelope() throws Exception {
		LmdbEvaluationStatistics statistics = new LmdbEvaluationStatistics(null, null, null, null, null, null);
		Object productEstimate = boundJoinProductEstimate(267.0d, 20_000.0d, 745_100.0d, 9_900.0d, "drug",
				false);
		JoinFactorCostModel.FactorCostEstimate baseEstimate = exactStatementProbeEstimate();

		Object blend = invokeBlend(statistics, productEstimate, 267.0d, 20_000.0d, 20_000.0d, 1.0d, 1.0d,
				baseEstimate);

		assertNotNull(blend, "Exact statement probes should retain the access-path envelope signal.");
		assertTrue(doubleRecordValue(blend, "outputRows") < 20_000.0d,
				"Exact statement lookup output should keep tuple-sketch selectivity below the probe envelope.");
		assertTrue(doubleRecordValue(blend, "workRows") >= 20_000.0d,
				"Exact statement lookup work still has to account for one probe per repeated invocation.");
	}

